import sys

def main():
    data = sys.stdin.buffer.read().split()
    idx = 0

    N = int(data[idx]); idx += 1
    M = int(data[idx]); idx += 1

    parent = list(range(N + 1))
    rank = [0] * (N + 1)

    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x

    def union(x, y):
        rx, ry = find(x), find(y)
        if rx == ry:
            return
        if rank[rx] < rank[ry]:
            rx, ry = ry, rx
        parent[ry] = rx
        if rank[rx] == rank[ry]:
            rank[rx] += 1

    for i in range(M):
        u = int(data[idx]); idx += 1
        v = int(data[idx]); idx += 1
        union(u, v)

    K = int(data[idx]); idx += 1

    forbidden = set()
    for i in range(K):
        x = int(data[idx]); idx += 1
        y = int(data[idx]); idx += 1
        rx, ry = find(x), find(y)
        if rx > ry:
            rx, ry = ry, rx
        forbidden.add((rx, ry))

    Q = int(data[idx]); idx += 1

    out = []
    for i in range(Q):
        p = int(data[idx]); idx += 1
        q = int(data[idx]); idx += 1
        rp, rq = find(p), find(q)
        if rp == rq:
            out.append("Yes")
        else:
            if rp > rq:
                rp, rq = rq, rp
            if (rp, rq) in forbidden:
                out.append("No")
            else:
                out.append("Yes")

    sys.stdout.write('\n'.join(out) + '\n')

main()

import sys

def solve():
    input = sys.stdin.readline
    N = int(input())
    A = list(map(int, input().split()))
    S = input().strip()

    mex_table = [[[0]*3 for _ in range(3)] for _ in range(3)]
    for a in range(3):
        for b in range(3):
            for c in range(3):
                s = {a, b, c}
                m = 0
                while m in s:
                    m += 1
                mex_table[a][b][c] = m

    countX = [0, 0, 0]
    for i in range(N):
        if S[i] == 'X':
            countX[A[i]] += 1

    countM = [0, 0, 0]
    answer = 0

    for j in range(N):
        if S[j] == 'X':
            countX[A[j]] -= 1

        if S[j] == 'E':
            e = A[j]
            for m in range(3):
                cm = countM[m]
                if cm == 0:
                    continue
                for x in range(3):
                    cx = countX[x]
                    if cx == 0:
                        continue
                    answer += cm * cx * mex_table[m][e][x]

        if S[j] == 'M':
            countM[A[j]] += 1

    print(answer)

solve()

import sys

def main():
    data = sys.stdin.buffer.read().split()
    idx = 0
    N, M = int(data[0]), int(data[1])
    idx = 2

    children = [[] for _ in range(N + 1)]
    for i in range(2, N + 1):
        p = int(data[idx]); idx += 1
        children[p].append(i)

    cov = [-1] * (N + 1)

    for _ in range(M):
        x = int(data[idx]); idx += 1
        y = int(data[idx]); idx += 1
        if y > cov[x]:
            cov[x] = y

    ans = 0
    for v in range(1, N + 1):
        if cov[v] >= 0:
            ans += 1
        if cov[v] > 0:
            d = cov[v] - 1
            for c in children[v]:
                if d > cov[c]:
                    cov[c] = d

    print(ans)

