import sys
from bisect import bisect_left

def main():
    data = sys.stdin.buffer.read().decode().split()
    idx = 0
    N = int(data[idx]); idx += 1
    T = data[idx]; idx += 1
    m = len(T)

    S = []
    for i in range(N):
        S.append(data[idx]); idx += 1

    prefixes = []
    for s in S:
        ptr = 0
        for c in s:
            if ptr < m and c == T[ptr]:
                ptr += 1
        prefixes.append(ptr)

    suffixes = []
    for s in S:
        ptr = m
        for c in reversed(s):
            if ptr > 0 and c == T[ptr - 1]:
                ptr -= 1
        suffixes.append(m - ptr)

    sorted_suf = sorted(suffixes)

    ans = 0
    for p in prefixes:
        need = m - p
        if need <= 0:
            ans += N
        else:
            pos = bisect_left(sorted_suf, need)
            ans += N - pos

    print(ans)

main()
